/**
 * proyectos.js — RobotikSD
 * Renders projects, videos, images and PDFs from JSON data files
 * generated by Decap CMS from Markdown front-matter.
 *
 * DATA FLOW:
 *   Decap CMS → saves .md files in content/proyectos/
 *   A build step (or netlify plugin) compiles them to data/*.json
 *   This JS reads the JSON and builds the UI
 *
 * FOR LOCAL / GITHUB PAGES (no build tool):
 *   Edit js/data.js manually OR use the CMS which auto-generates it.
 */

// ─── CONFIG ─────────────────────────────────────────────────────────────────
const DATA_URL    = 'js/data.json';   // Auto-generated from CMS content
const YOUTUBE_NOCOOKIE = 'https://www.youtube-nocookie.com/embed/';

// ─── STATE ──────────────────────────────────────────────────────────────────
let allProjects = [];
let allVideos   = [];
let allImages   = [];
let allPDFs     = [];
let activeFilter = 'all';

// ─── BOOTSTRAP ──────────────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', async () => {
  await loadData();
  initFilters();
  initMediaTabs();
  initLightbox();
  renderAll();
  updateStats();
});

// ─── DATA LOADING ───────────────────────────────────────────────────────────
async function loadData() {
  try {
    const res  = await fetch(DATA_URL + '?t=' + Date.now());
    const data = await res.json();
    allProjects = data.projects  || [];
    allVideos   = data.videos    || [];
    allImages   = data.images    || [];
    allPDFs     = data.pdfs      || [];
  } catch (e) {
    console.warn('No data.json found — using sample data.', e);
    loadSampleData();
  }
}

