// ─── FILTERS ────────────────────────────────────────────────────────────────
function initFilters() {
  document.querySelectorAll('#filter-bar .filter-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('#filter-bar .filter-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      activeFilter = btn.dataset.filter;
      renderProjects();
    });
  });
}

// ─── MEDIA TABS ─────────────────────────────────────────────────────────────
function initMediaTabs() {
  document.querySelectorAll('#media-tabs .media-tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('#media-tabs .media-tab-btn').forEach(b => b.classList.remove('active'));
      document.querySelectorAll('.media-panel').forEach(p => p.classList.add('hidden'));
      btn.classList.add('active');
      document.getElementById('panel-' + btn.dataset.tab).classList.remove('hidden');
    });
  });
}

// ─── RENDER ALL ─────────────────────────────────────────────────────────────
function renderAll() {
  renderProjects();
  renderVideos();
  renderGallery();
  renderPDFs();
}

// ─── RENDER PROJECTS ────────────────────────────────────────────────────────
function renderProjects() {
  const grid  = document.getElementById('projects-grid');
  const empty = document.getElementById('projects-empty');
  const filtered = activeFilter === 'all'
    ? allProjects
    : allProjects.filter(p => p.category === activeFilter);

  grid.innerHTML = '';

  if (!filtered.length) {
    grid.classList.add('hidden');
    empty.classList.remove('hidden');
    return;
  }
  grid.classList.remove('hidden');
  empty.classList.add('hidden');

  filtered.forEach(p => {
    const card = document.createElement('div');
    card.className = 'proj-card';
    card.innerHTML = `
      ${p.image
        ? `<img src="${p.image}" alt="${p.title}" class="proj-thumb" loading="lazy" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
        : ''}
      <div class="proj-thumb-placeholder" style="background:${p.gradient || 'linear-gradient(135deg,#111c2d,#1f2a3c)'}; ${p.image ? 'display:none' : ''}">
        ${p.emoji || '🔧'}
      </div>
      <div class="proj-body">
        <span class="proj-cat">${categoryLabel(p.category)}</span>
        <div class="proj-title">${p.title}</div>
        <div class="proj-desc">${p.description}</div>
        ${p.tags?.length ? `<div class="proj-tags">${p.tags.map(t => `<span class="proj-tag">${t}</span>`).join('')}</div>` : ''}
        <div class="proj-icons">
          ${p.hasVideo ? `<span class="proj-icon-badge"><span class="material-symbols-outlined">smart_display</span> Vídeo</span>` : ''}
          ${p.hasPDF   ? `<span class="proj-icon-badge"><span class="material-symbols-outlined">picture_as_pdf</span> PDF</span>` : ''}
          ${p.course   ? `<span class="proj-icon-badge" style="margin-left:auto;font-size:0.68rem;color:#414754">${p.course}</span>` : ''}
        </div>
      </div>
    `;
    grid.appendChild(card);
  });
}

function categoryLabel(cat) {
  const map = { robotica:'Robótica', scratch:'Scratch', arduino:'Arduino', python:'Python', ia:'Inteligencia Artificial', web:'Desarrollo Web' };
  return map[cat] || cat;
}

// ─── RENDER VIDEOS ──────────────────────────────────────────────────────────
function renderVideos() {
  const grid  = document.getElementById('videos-grid');
  const empty = document.getElementById('videos-empty');
  if (!allVideos.length) { grid.classList.add('hidden'); empty.classList.remove('hidden'); return; }

  grid.classList.remove('hidden');
  empty.classList.add('hidden');
  grid.innerHTML = '';

  allVideos.forEach(v => {
    const embedId = extractYoutubeId(v.youtubeId || v.url || '');
    const card = document.createElement('div');
    card.className = 'video-card';
    card.innerHTML = `
      <div class="video-wrapper">
        <iframe
          src="${YOUTUBE_NOCOOKIE}${embedId}?rel=0&modestbranding=1"
          title="${v.title}"
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowfullscreen
          loading="lazy">
        </iframe>
      </div>
      <div class="video-info">
        <div class="video-title">${v.title}</div>
        ${v.description ? `<div class="video-desc">${v.description}</div>` : ''}
      </div>
    `;
    grid.appendChild(card);
  });
}

function extractYoutubeId(str) {
  // Accepts raw ID, full URL, or youtu.be short URL
  const patterns = [
    /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/,
    /^([a-zA-Z0-9_-]{11})$/
  ];
  for (const p of patterns) {
    const m = str.match(p);
    if (m) return m[1];
  }
  return str;
}

// ─── RENDER GALLERY ─────────────────────────────────────────────────────────
function renderGallery() {
  const grid  = document.getElementById('gallery-grid');
  const empty = document.getElementById('gallery-empty');
  if (!allImages.length) { grid.classList.add('hidden'); empty.classList.remove('hidden'); return; }

  grid.classList.remove('hidden');
  empty.classList.add('hidden');
  grid.innerHTML = '';

  allImages.forEach(img => {
    const item = document.createElement('div');
    item.className = 'gallery-item';
    item.onclick = () => openLightbox(img.src, img.alt);
    item.innerHTML = `<img src="${img.src}" alt="${img.alt}" loading="lazy" onerror="this.closest('.gallery-item').style.display='none'">`;
    grid.appendChild(item);
  });
}

// ─── RENDER PDFs ────────────────────────────────────────────────────────────
function renderPDFs() {
  const list  = document.getElementById('pdfs-list');
  const empty = document.getElementById('pdfs-empty');
  if (!allPDFs.length) { list.classList.add('hidden'); empty.classList.remove('hidden'); return; }

  list.classList.remove('hidden');
  empty.classList.add('hidden');
  list.innerHTML = '';

  allPDFs.forEach(pdf => {
    const card = document.createElement('a');
    card.className = 'pdf-card';
    card.href = pdf.url;
    card.target = '_blank';
    card.rel = 'noopener noreferrer';
    card.innerHTML = `
      <div class="pdf-icon"><span class="material-symbols-outlined" style="font-variation-settings:'FILL' 1">picture_as_pdf</span></div>
      <div class="pdf-meta">
        <div class="pdf-name">${pdf.name}</div>
        <div class="pdf-size">${pdf.description || ''} ${pdf.size ? '· ' + pdf.size : ''}</div>
      </div>
      <div class="pdf-dl"><span class="material-symbols-outlined">download</span></div>
    `;
    list.appendChild(card);
  });
}

// ─── STATS ──────────────────────────────────────────────────────────────────
function updateStats() {
  const animCount = (el, target) => {
    if (!el) return;
    let n = 0;
    const step = Math.max(1, Math.floor(target / 30));
    const t = setInterval(() => {
      n = Math.min(n + step, target);
      el.textContent = n;
      if (n >= target) clearInterval(t);
    }, 40);
  };
  animCount(document.getElementById('stat-proyectos'), allProjects.length);
  animCount(document.getElementById('stat-videos'),    allVideos.length);
  animCount(document.getElementById('stat-fotos'),     allImages.length);
}

// ─── LIGHTBOX ───────────────────────────────────────────────────────────────
function initLightbox() {
  document.getElementById('lightbox').addEventListener('click', e => {
    if (e.target.id === 'lightbox') closeLightbox();
  });
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') closeLightbox();
  });
}

function openLightbox(src, alt) {
  const lb = document.getElementById('lightbox');
  document.getElementById('lb-img').src = src;
  document.getElementById('lb-img').alt = alt || '';
  lb.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeLightbox() {
  document.getElementById('lightbox').classList.remove('open');
  document.body.style.overflow = '';
}
